node_types

{"training": ["gpu"], "workspace": ["cpu"]}

    Set the gpu, cpu, and memory resources for a given nodepool.
    CPU/Memory may not work if your organization does not permit assiging these resources

    "nodePool": {
        id: str
        name: str
    },
    "gpu": {
        deserved: int
        limit: int
        overQuotaWeight: int
    },
    "cpu": {
        "deserved": int,
        "limit": int,
        "overQuotaWeight": int
    },
        "memory": {
            "deserved": int,
            "limit": int,
            "overQuotaWeight": int,
            "units": "Mib" or "GB" or "MB,
    }

    Example:
    {
        {
            "nodePool": {
            "id": 22,
            "name": "default"
        },
            "gpu": {
            "deserved": 1000,
            "limit": 0,
            "overQuotaWeight": 2
        },
            "cpu": {
            "deserved": 1000,
            "limit": 0,
            "overQuotaWeight": 2
        },
            "memory": {
            "deserved": 1000,
            "limit": 0,
            "overQuotaWeight": 2,
            "units": "Mib"
        }
}
    }
